### What are API Routes?

API Routes let you build a backend API inside your Next.js application. Files in `pages/api/` are treated as API endpoints instead of pages.

### Basic API Route

```jsx
// pages/api/hello.js
export default function handler(req, res) {
  res.status(200).json({ message: 'Hello World' });
}
```

Access it at `http://localhost:3000/api/hello`.

### Request and Response

The handler receives:
- `req` — NextApiRequest (extends IncomingMessage)
- `res` — NextApiResponse (extends ServerResponse)

```jsx
export default function handler(req, res) {
  const { method } = req;

  switch (method) {
    case 'GET':
      // handle GET
      break;
    case 'POST':
      // handle POST
      break;
    default:
      res.setHeader('Allow', ['GET', 'POST']);
      res.status(405).end(`Method ${method} Not Allowed`);
  }
}
```

### Dynamic API Routes

Same file-based routing applies:

```jsx
// pages/api/posts/[id].js
export default function handler(req, res) {
  const { id } = req.query;

  if (req.method === 'GET') {
    const post = getPostById(id);
    if (!post) {
      return res.status(404).json({ error: 'Post not found' });
    }
    res.status(200).json(post);
  }

  if (req.method === 'PUT') {
    updatePost(id, req.body);
    res.status(200).json({ message: 'Updated' });
  }
}
```

### Middleware Patterns

Apply middleware for common functionality:

```jsx
// middleware/auth.js
export function withAuth(handler) {
  return async (req, res) => {
    const token = req.headers.authorization;

    if (!token) {
      return res.status(401).json({ error: 'Unauthorized' });
    }

    const user = await verifyToken(token);
    req.user = user;
    return handler(req, res);
  };
}

// pages/api/profile.js
import { withAuth } from '../../middleware/auth';

async function handler(req, res) {
  res.status(200).json({ user: req.user });
}

export default withAuth(handler);
```

### Database Connection

```jsx
import { connectToDatabase } from '../../lib/db';

export default async function handler(req, res) {
  const { db } = await connectToDatabase();

  if (req.method === 'GET') {
    const posts = await db.collection('posts').find({}).toArray();
    return res.status(200).json(posts);
  }

  if (req.method === 'POST') {
    const post = await db.collection('posts').insertOne(req.body);
    return res.status(201).json(post);
  }
}
```

